input.command:
cd /home/briney/git/fold-at-scripps
for t in ablang2 boltz2; do
  echo "=== autobio info $t (input_schema, trimmed) ==="
  autobio info "$t" --format json 2>/dev/null | python -c "
import sys, json
d = json.load(sys.stdin)
sch = d.get('input_schema') or {}
props = sch.get('properties', {})
print('required:', sch.get('required'))
for k, v in props.items():
    if isinstance(v, dict):
        kind = v.get('type') or ('anyOf:'+str([a.get('type') for a in v.get('anyOf',[])]) if 'anyOf' in v else '?')
        extra = []
        if v.get('format'): extra.append('format='+v['format'])
        if 'default' in v: extra.append('default='+repr(v['default']))
        if v.get('enum'): extra.append('enum='+str(v['enum']))
        print(f'  {k}: {kind} {\" \".join(extra)}')
" 2>/dev/null
  echo
done

