744	- [ ] **Step 3: Implement `build-zod.ts`**
745	
746	```ts
747	import { z } from "zod";
748	import type { JsonSchema } from "@/types/api";
749	
750	function unwrapNullable(schema: JsonSchema): { inner: JsonSchema; nullable: boolean } {
751	  if (Array.isArray(schema.anyOf)) {
752	    const nonNull = schema.anyOf.filter((s) => s.type !== "null");
753	    const nullable = schema.anyOf.some((s) => s.type === "null");
754	    if (nonNull.length === 1) return { inner: nonNull[0], nullable };
755	  }
756	  return { inner: schema, nullable: false };
757	}
758	
759	function isScalar(schema: JsonSchema): boolean {
760	  return (
761	    schema.type === "string" || schema.type === "integer" ||
762	    schema.type === "number" || schema.type === "boolean"
763	  );
764	}
765	
766	function fieldZod(schema: JsonSchema): z.ZodTypeAny {
767	  const { inner, nullable } = unwrapNullable(schema);
768	  let base: z.ZodTypeAny;
769	  if (Array.isArray(inner.enum) && inner.enum.length > 0) {
770	    base = z.enum(inner.enum.map(String) as [string, ...string[]]);
771	  } else if (inner.type === "string") {
772	    base = z.string();
773	  } else if (inner.type === "integer" || inner.type === "number") {
774	    let num = z.number();
775	    if (inner.type === "integer") num = num.int();
776	    if (typeof inner.minimum === "number") num = num.min(inner.minimum);
777	    if (typeof inner.maximum === "number") num = num.max(inner.maximum);
778	    base = num;
779	  } else if (inner.type === "boolean") {
780	    base = z.boolean();
781	  } else if (inner.type === "array" && inner.items && isScalar(inner.items)) {
782	    base = z.array(fieldZod(inner.items));
783	  } else {
784	    base = z.unknown(); // objects, arrays-of-objects, additionalProperties: server-validated
785	  }
786	  return nullable ? base.nullable() : base;
787	}
788	
789	export function buildZodSchema(schema: JsonSchema): z.ZodType {
790	  const properties = schema.properties ?? {};
791	  const required = new Set(schema.required ?? []);
792	  const shape: Record<string, z.ZodTypeAny> = {};
793	  for (const [key, prop] of Object.entries(properties)) {
794	    const field = fieldZod(prop);
795	    shape[key] = required.has(key) ? field : field.optional();
796	  }
797	  return z.object(shape).passthrough();
798	}
799	```
